/// <summary>
/// Extension Form class for InventTransferOrders
/// </summary>
[ExtensionOf(formStr(InventTransferOrders))]
final class KJP_SM_InventTransferOrdersForm_Extension
{
}

Method.Source:
/// <summary>
/// Init InventTransferOrders Form
/// </summary>
public void init()
{
    next init();
    if(KJP_CM_Utils::checkCurExtIsKKC())
    {
        // 2.2.1.2.3 Add 1st Line: Line ShipDate and ReceiveDate not editable
        InventTransferLine_ds.object(fieldNum(InventTransferLine, ShipDate)).allowEdit(False);
        InventTransferLine_ds.object(fieldNum(InventTransferLine, ReceiveDate)).allowEdit(False); 
        // 2.2.1.1.3 Field Mapping No13,14
        InventTransferLine_ds.object(fieldNum(InventTransferLine, KJPSMShippingInstructionSendingFlag)).allowEdit(False);
        InventTransferLine_ds.object(fieldNum(InventTransferLine, KJPSMStockArrivalScheduleSendingFlag)).allowEdit(False); 
    }      
}
